import React from "react";
import { useNavigate } from "react-router-dom";

interface SidebarProps {
    activeLink: string;
    onLinkClick: (link: string) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ activeLink, onLinkClick }) => {
    const navigate = useNavigate();

    const menuItems = [
        { name: "Real-Time Pricing", path: "/real-time-pricing" },
        { name: "Inventory", path: "/inventory" },
        { name: "Alerts", path: "/alerts" },
        { name: "Analytics", path: "/analytics" },
        { name: "Settings", path: "/settings" },
        { name: "Help", path: "/help" },
    ];

    return (
        <div className="sidebar-container">
            {menuItems.map((item) => (
                <button
                    key={item.name}
                    onClick={() => {
                        onLinkClick(item.path);
                        navigate(item.path);
                    }}
                    className={activeLink === item.path ? "active" : ""}
                >
                    {item.name}
                </button>
            ))}
            <button className="logout-button" onClick={() => console.log("Logout işlemi")}>
                LOGOUT
            </button>
        </div>
    );
};

export default Sidebar;
